module RefModule(datain, dataout, clock, load);
input [4:0] datain;
output [4:0] dataout;
input clock, load;
reg [4:0] dataout;
  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always@(posedge clock or posedge dbg_halt)
begin
    if(load)
       dataout <= datain;
    else
       dataout <= 5'b0;
end
endmodule
